$file = "app\src\main\java\com\example\mobile\presentation\viewmodel\HabitDetailViewModel.kt"
$content = Get-Content $file -Raw; if ($content -match 'import kotlinx\.coroutines\.Dispatchers') { Write-Host "Dispatchers import already present" } else { $content = $content -replace 'import kotlinx\.coroutines\.Job', 'import kotlinx.coroutines.Dispatchers`nimport kotlinx.coroutines.Job'; Write-Host "Added Dispatchers import" }; $content = $content -replace 'timerJob = viewModelScope\.launch \{', 'timerJob = viewModelScope.launch(Dispatchers.Default) {'; Set-Content $file $content -NoNewline; Write-Host "Done"
